import { x402Client, wrapFetchWithPayment } from "@x402/fetch";
import { ExactEvmScheme } from "@x402/evm/exact/client";
import { privateKeyToAccount } from "viem/accounts";

const BASE_URL = "https://q-api.quotient.social";
const signer = privateKeyToAccount(process.env.EVM_PRIVATE_KEY as `0x${string}`);

const client = new x402Client();
client.register("eip155:*", new ExactEvmScheme(signer));
const fetchWithPayment = wrapFetchWithPayment(fetch, client);

// Find mispriced markets (Quotient odds vs. market odds)
const res = await fetchWithPayment(`${BASE_URL}/api/v1/markets/mispriced`);
const { markets } = await res.json();

// Or use an API key directly (no x402 needed)
const intel = await fetch(`${BASE_URL}/api/v1/markets/${slug}/intelligence`, {
  headers: { "x-quotient-api-key": process.env.QUOTIENT_API_KEY! }
});
